28	 * @author BetaSteward_at_googlemail.com
29	 */
30	public class ManaPool implements Serializable {
31	
32	    private final UUID playerId;
33	
34	    private final List<ManaPoolItem> manaItems = new ArrayList<>();
35	
36	    private boolean autoPayment; // auto payment from mana pool: true - mode is active
37	    private boolean autoPaymentRestricted; // auto payment from mana pool: true - if auto Payment is on, it will only pay if one kind of mana is in the pool
38	    private ManaType unlockedManaType; // type of mana that was selected to pay manually
39	    private boolean forcedToPay; // for Word of Command
40	    private final List<ManaPoolItem> poolBookmark = new ArrayList<>(); // mana pool bookmark for rollback purposes
41	
42	    // empty mana pool effects
43	    private final Set<ManaType> doNotEmptyManaTypes = new HashSet<>(); // keep some colors
44	    private boolean manaBecomesBlack = false; // replace all pool by black
45	    private boolean manaBecomesRed = false; // replace all pool by red
46	    private boolean manaBecomesColorless = false; // replace all pool by colorless
47	
48	    private static final class ConditionalManaInfo {
49	        private final ManaType manaType;
50	        private final MageObject sourceObject;
51	
52	        private ConditionalManaInfo(ManaType conditionalMana, MageObject sourceObject) {
53	            this.manaType = conditionalMana;
54	            this.sourceObject = sourceObject;
55	        }
56	    }
57	
58	    public ManaPool(UUID playerId) {
59	        this.playerId = playerId;
60	        autoPayment = true;
61	        autoPaymentRestricted = true;
62	        unlockedManaType = null;
63	        forcedToPay = false;
64	    }
65	
66	    protected ManaPool(final ManaPool pool) {
67	        this.playerId = pool.playerId;
68	        for (ManaPoolItem item : pool.manaItems) {
69	            manaItems.add(item.copy());
70	        }
71	        this.autoPayment = pool.autoPayment;
72	        this.autoPaymentRestricted = pool.autoPaymentRestricted;
73	        this.unlockedManaType = pool.unlockedManaType;
74	        this.forcedToPay = pool.forcedToPay;
75	        for (ManaPoolItem item : pool.poolBookmark) {
76	            poolBookmark.add(item.copy());
77	        }
78	        this.doNotEmptyManaTypes.addAll(pool.doNotEmptyManaTypes);
79	        this.manaBecomesBlack = pool.manaBecomesBlack;
80	        this.manaBecomesRed = pool.manaBecomesRed;
81	        this.manaBecomesColorless = pool.manaBecomesColorless;
82	    }
