192	    private ConditionalManaInfo getConditional(ManaType manaType, Ability ability, Filter filter, Game game, Cost costToPay, ManaType possibleAsThoughPoolManaType) {
193	        if (ability == null || getConditionalMana().isEmpty()) {
194	            return null;
195	        }
196	        for (ManaPoolItem mana : manaItems) {
197	            if (mana.isConditional()) {
198	                ManaType manaTypeToUse = null;
199	                if (mana.getConditionalMana().get(manaType) > 0) {
200	                    manaTypeToUse = manaType;
201	                } else {
202	                    if (possibleAsThoughPoolManaType == null) {
203	                        possibleAsThoughPoolManaType = game.getContinuousEffects().asThoughMana(manaType, mana, ability.getSourceId(), ability, ability.getControllerId(), game);
204	                    }
205	                    if (possibleAsThoughPoolManaType != null && mana.getConditionalMana().get(possibleAsThoughPoolManaType) > 0) {
206	                        manaTypeToUse = possibleAsThoughPoolManaType;
207	                    }
208	                }
209	                if (manaTypeToUse != null && mana.getConditionalMana().apply(ability, game, mana.getSourceId(), costToPay)) {
210	                    if (filter == null || filter.match(mana.getSourceObject(), game)) {
211	                        return new ConditionalManaInfo(manaTypeToUse, mana.getSourceObject());
212	                    }
213	                }
214	            }
215	        }
216	
217	        return null;
218	    }
219	
220	    public int getConditionalCount(Ability ability, Game game, FilterMana filter, Cost costToPay) {
221	        if (ability == null
222	                || getConditionalMana().isEmpty()) {
223	            return 0;
224	        }
225	        int count = 0;
226	        for (ConditionalMana mana : getConditionalMana()) {
227	            if (mana.apply(ability, game, mana.getManaProducerId(), costToPay)) {
228	                count += mana.count(filter);
229	            }
230	        }
231	        return count;
232	    }
