265	    public boolean canLostManaOnEmpty() {
266	        for (ManaPoolItem item : manaItems) {
267	            for (ManaType manaType : ManaType.values()) {
268	                if (item.get(manaType) == 0) {
269	                    continue;
270	                }
271	                if (doNotEmptyManaTypes.contains(manaType)) {
272	                    continue;
273	                }
274	                if (manaBecomesBlack) {
275	                    continue;
276	                }
277	                if (manaBecomesRed) {
278	                    continue;
279	                }
280	                if (manaBecomesColorless) {
281	                    continue;
282	                }
283	                // found real mana to empty
284	                return true;
285	            }
286	        }
287	        return false;
288	    }
289	
290	    public int emptyPool(Game game) {
291	        int total = 0;
292	        Iterator<ManaPoolItem> it = manaItems.iterator();
293	        while (it.hasNext()) {
294	            ManaPoolItem item = it.next();
295	            ConditionalMana conditionalItem = item.getConditionalMana();
296	            for (ManaType manaType : ManaType.values()) {
297	                if (doNotEmptyManaTypes.contains(manaType)) {
298	                    continue;
299	                }
300	                if (item.get(manaType) > 0) {
301	                    total += emptyItem(item, item, game, manaType);
302	                }
303	                if (conditionalItem != null
304	                        && conditionalItem.get(manaType) > 0) {
305	                    total += emptyItem(item, conditionalItem, game, manaType);
306	                }
307	            }
308	            if (item.count() == 0) {
309	                it.remove();
310	            }
311	        }
312	        return total;
313	    }
314	
315	    private int emptyItem(ManaPoolItem item, Emptiable toEmpty, Game game, ManaType manaType) {
316	        switch (item.getDuration()) {
317	            case EndOfTurn:
318	                if (game.getTurnPhaseType() != TurnPhase.END) {
319	                    return 0;
320	                }
321	                break;
322	            case EndOfCombat:
323	                if (game.getTurnPhaseType() != TurnPhase.COMBAT
324	                        || game.getTurnStepType() != PhaseStep.END_COMBAT) {
325	                    return 0;
326	                }
327	        }
328	
329	        // TODO: This should be reimplemented as replacement effects instead, so you can choose which applies.
330	        if (manaBecomesBlack) {
331	            int amount = toEmpty.get(manaType);
332	            toEmpty.clear(manaType);
333	            toEmpty.add(ManaType.BLACK, amount);
334	            return 0;
335	        }
336	        if (manaBecomesRed) {
337	            int amount = toEmpty.get(manaType);
338	            toEmpty.clear(manaType);
339	            toEmpty.add(ManaType.RED, amount);
340	            return 0;
341	        }
342	        if (manaBecomesColorless) {
343	            int amount = toEmpty.get(manaType);
344	            toEmpty.clear(manaType);
345	            toEmpty.add(ManaType.COLORLESS, amount);
346	            return 0;
347	        }
348	        int amount = toEmpty.get(manaType);
349	        toEmpty.clear(manaType);
350	        return amount;
351	    }
