399	    public void addMana(Mana manaToAdd, Game game, Ability source, Duration duration) {
400	        if (manaToAdd != null) {
401	            Mana mana = manaToAdd.copy();
402	            if (!game.replaceEvent(new ManaEvent(EventType.ADD_MANA, source.getId(), source, playerId, mana))) {
403	                if (mana instanceof ConditionalMana) {
404	                    ConditionalMana conditionalMana = (ConditionalMana) mana;
405	                    ManaPoolItem item = new ManaPoolItem(
406	                            conditionalMana,
407	                            source.getSourceObject(game),
408	                            conditionalMana.getManaProducerOriginalId() != null ? conditionalMana.getManaProducerOriginalId() : source.getOriginalId()
409	                    );
410	                    if (duration != null) {
411	                        item.setDuration(duration);
412	                    }
413	                    this.manaItems.add(item);
414	                } else {
415	                    ManaPoolItem item = new ManaPoolItem(
416	                            mana.getRed(),
417	                            mana.getGreen(),
418	                            mana.getBlue(),
419	                            mana.getWhite(),
420	                            mana.getBlack(),
421	                            mana.getGeneric() + mana.getColorless(),
422	                            source.getSourceObject(game),
423	                            source.getOriginalId(),
424	                            mana.getFlag()
425	                    );
426	                    if (duration != null) {
427	                        item.setDuration(duration);
428	                    }
429	                    this.manaItems.add(item);
430	                }
431	                ManaEvent manaEvent = new ManaEvent(EventType.MANA_ADDED, source.getId(), source, playerId, mana);
432	                manaEvent.setData(mana.toString());
433	                game.fireEvent(manaEvent);
434	            }
435	        }
436	    }
