package org.mage.test.cards.single.iko;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author TheElk801
 */
public class JeganthaTheWellspringTest extends CardTestPlayerBase {

    private static final String jegantha = "Jegantha, the Wellspring";
    private static final String honden = "Honden of Infinite Rage";

    @Test
    public void testJeganthaManaCanPayColoredCostBeforeGeneric() {
        // Test that Jegantha's mana can be used to pay colored costs
        // even when generic costs are still unpaid.
        // Scenario: 2 Mountains + Jegantha on field, casting Honden of Infinite Rage (2R)
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);
        addCard(Zone.BATTLEFIELD, playerA, jegantha);

        addCard(Zone.HAND, playerA, honden);

        // Tap Jegantha for WUBRG
        activateManaAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}: Add {W}{U}{B}{R}{G}");

        // Cast Honden of Infinite Rage (2R) - Jegantha's mana should pay for R,
        // Mountains should pay for the generic costs
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, honden);

        setStopAt(1, PhaseStep.BEGIN_COMBAT);
        execute();

        assertTapped(jegantha, true);
        assertTappedCount("Mountain", true, 2);
        assertPermanentCount(playerA, honden, 1);
    }

    @Test
    public void testJeganthaManaTappedDuringPayment() {
        // Same scenario but with Jegantha tapped during payment (auto-pay)
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);
        addCard(Zone.BATTLEFIELD, playerA, jegantha);

        addCard(Zone.HAND, playerA, honden);

        // Cast Honden of Infinite Rage (2R) - auto-pay should tap Jegantha for R
        // and Mountains for generic
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, honden);

        setStopAt(1, PhaseStep.BEGIN_COMBAT);
        execute();

        assertTapped(jegantha, true);
        assertTappedCount("Mountain", true, 2);
        assertPermanentCount(playerA, honden, 1);
    }

    @Test
    public void testJeganthaCantPayGenericCosts() {
        // If only generic costs remain, Jegantha's mana can't be used
        // Scenario: 2 Mountains + Jegantha, but one Mountain is used to pay R first,
        // then Jegantha's mana should not be usable for the generic 2
        // Actually, we test that Jegantha's mana can't pay for a fully generic spell like Wastes
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);
        addCard(Zone.BATTLEFIELD, playerA, jegantha);

        // Wastes costs 2 (fully generic). We'll try to cast it with Jegantha + 2 Mountains.
        // This test verifies Jegantha's mana can still help (by tapping for the colored part
        // but there is no colored part)
        // Let's use a different approach: test that Jegantha mana can't be used for a
        // spell that only has generic costs
        addCard(Zone.HAND, playerA, "Memnite", 1);  // {0} - free, should work regardless

        // Actually, let's test with a card that costs {3} (only generic)
        addCard(Zone.HAND, playerA, "Fractured Powerstone", 1);  // {2} cost

        // Tap Jegantha, but since Fractured Powerstone has only generic cost (2),
        // Jegantha's mana shouldn't be usable
        activateManaAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}: Add {W}{U}{B}{R}{G}");

        // This should still be castable since we have 2 Mountains
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Fractured Powerstone");

        setStopAt(1, PhaseStep.BEGIN_COMBAT);
        execute();

        // Fractured Powerstone should be cast with the 2 Mountains
        assertTappedCount("Mountain", true, 2);
        // Jegantha should remain untapped since its mana can't pay generic costs
        assertTapped(jegantha, false);
        assertPermanentCount(playerA, "Fractured Powerstone", 1);
    }
}

