class JeganthaManaCondition extends ManaCondition {

    @Override
    public boolean apply(Game game, Ability source, UUID originalId, Cost costsToPay) {
        // Jegantha's mana can't be spent to pay generic mana costs.
        // It can only be used while there are non-generic, non-variable costs remaining to be paid.
        ManaCosts<ManaCost> unpaid = source.getManaCostsToPay().getUnpaid();
        if (!unpaid.isEmpty()) {
            return hasNonGenericCost(unpaid);
        }
        // If mana costs to pay isn't set up yet (e.g., pre-casting check), use base mana costs
        return hasNonGenericCost(source.getManaCosts());
    }

    private boolean hasNonGenericCost(ManaCosts<ManaCost> costs) {
        for (ManaCost cost : costs) {
            if (!(cost instanceof GenericManaCost) && !(cost instanceof VariableManaCost)) {
                return true;
            }
        }
        return false;
    }
}

