        // {T}: Add {W}{U}{B}{R}{G}. This mana can't be spent to pay generic mana costs.
        this.addAbility(new ConditionalColoredManaAbility(
                new TapSourceCost(), new Mana(1, 1, 1, 1, 1, 0, 0, 0), new JeganthaManaBuilder()
        ));
